}

function ConnectionConfigScreen({ go, params }) {
  const { Card, Input, Select, Button } = DQconn;
  const { PageHeader } = window;
  const type = (params && params.type) || 'snowflake';
  const spec = FORM_SPECS[type];
  const m = SOURCE_META[type];
  const [authType, setAuthType] = React.useState(spec.auth ? spec.auth[0].value : null);
  const [testState, setTestState] = React.useState(null);
  const auth = spec.auth ? spec.auth.find((a) => a.value === authType) : null;
  const secretLabel = auth ? auth.secretLabel : spec.secretLabel;

  return (
    <div style={{ maxWidth: 720, margin: '0 auto' }}>
      <PageHeader backLabel="Select source" onBack={() => go('connection-source')}
        title="Configure Connection" subtitle={`${m.label} · ${m.cat}`} />
      <Card padding={24}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 12, padding: '12px 14px', background: 'var(--bg-subtle)', borderRadius: 'var(--radius)', border: '1px solid var(--border)', marginBottom: 20 }}>
          <div style={{ width: 34, height: 34, borderRadius: 8, background: `color-mix(in srgb, ${m.accent} 12%, #fff)`, color: m.accent, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>{React.createElement(window.Icon[m.icon], { size: 18 })}</div>
          <span style={{ fontSize: 14, fontWeight: 600, color: 'var(--text-primary)' }}>{m.label}</span>
        </div>

        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 16 }}>
          <Input label="Connection name" placeholder={`${m.label}_Prod_01`} mono style={{ gridColumn: '1 / -1' }} />
          {spec.textFields.map((f) => (
            <Input key={f.name} label={f.label + (f.optional ? ' (optional)' : '')} placeholder={f.name} mono />
          ))}
          {spec.auth && (
            <Select label="Authentication" options={spec.auth.map((a) => ({ value: a.value, label: a.label }))} value={authType} onChange={(e) => setAuthType(e.target.value)} />
          )}
          <Input label={secretLabel} type="password" placeholder="••••••••"
            hint={auth && auth.multilineSecret ? 'Paste the full PEM block.' : 'Stored encrypted in Azure Key Vault.'}
            style={{ gridColumn: spec.auth ? 'auto' : '1 / -1' }} />
        </div>

        {testState && (
          <div style={{ marginTop: 16, fontSize: 13, fontWeight: 500, color: testState === 'ok' ? 'var(--status-pass)' : 'var(--text-muted)' }}>
            {testState === 'ok' ? '✓ Connection succeeded · 12 schemas reachable' : 'Testing connection…'}
          </div>
        )}

        <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 10, marginTop: 24, paddingTop: 20, borderTop: '1px solid var(--divider)' }}>
          <Button variant="secondary" onClick={() => { setTestState('testing'); setTimeout(() => setTestState('ok'), 700); }}>Test Connection</Button>
          <Button variant="primary" onClick={() => go('connections')}>Save Connection</Button>
        </div>
      </Card>
    </div>
  );
}

Object.assign(window, { ConnectionSourceScreen, ConnectionConfigScreen });
