{"method":"get_file","path":"templates/app/SettingsScreen.jsx","content":"// DataQ — Workspace Settings. Tabbed: General, Secrets (Azure Key Vault),
// Notifications, Danger zone. Composes Card, Input, Select, Switch, Tag.
const DQset = window.DataQDesignSystem_317fec;

function SettingsTabs({ value, onChange, items }) {
  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: 2 }}>
      {items.map((it) => {
        const active = it === value;
        return (
          <button key={it} onClick={() => onChange(it)} style={{
            textAlign: 'left', padding: '9px 12px', border: 'none', borderRadius: 'var(--radius)', cursor: 'pointer',
            fontFamily: 'var(--font-sans)', fontSize: 14, fontWeight: active ? 600 : 500,
            color: active ? 'var(--indigo-600)' : 'var(--text-body)',
            background: active ? 'var(--bg-selected)' : 'transparent',
          }}>{it}</button>
        );
      })}
    </div>
  );
}

function Row({ label, hint, children }) {
  return (
    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', gap: 24, padding: '16px 0', borderBottom: '1px solid var(--divider)' }}>
      <div style={{ maxWidth: 320 }}>
        <div style={{ fontSize: 14, fontWeight: 500, color: 'var(--text-primary)' }}>{label}</div>
        {hint && <div style={{ fontSize: 13, color: 'var(--text-muted)', marginTop: 2 }}>{hint}</div>}
      </div>
      <div style={{ flex: 'none' }}>{children}</div>
    </div>
  );
}

function GeneralTab() {
  const { Input, Select } = DQset;
  return (
    <div style={{ maxWidth: 460, display: 'flex', flexDirection: 'column', gap: 16 }}>
      <Input label="Workspace name" defaultValue="acme-analytics" />
      <Select label="Default environment" options={['DEV', 'QA', 'UAT', 'PROD']} value="PROD" onChange={() => {}} />
      <Select label="Azure region" options={['East US 2', 'West Europe', 'Australia East']} value="East US 2" onChange={() => {}} />
      <Input label="Data Integrity SLA target" defaultValue="99.5" hint="Health score below this raises a workspace alert." />
    </div>
  );
}

function SecretsTab() {
  const { Card, Tag, Button } = DQset;
  const secrets = [
    { name: 'snowflake-prod-01-password', type: 'Password', rotated: '12d ago' },
    { name: 'aws-s3-landing-secret-key', type: 'Secret key', rotated: '3d ago' },
    { name: 'airflow-hmac-signing-key', type: 'HMAC key', rotated: '28d ago' },
  ];
  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
      <Card style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
        <div style={{ width: 38, height: 38, borderRadius: 8, background: 'var(--indigo-50)', color: 'var(--indigo-600)', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>{React.createElement(window.Icon.shield, { size: 20 })}</div>
        <div style={{ flex: 1 }}>
          <div style={{ fontSize: 14, fontWeight: 600, color: 'var(--text-primary)' }}>Azure Key Vault</div>
          <div style={{ fontSize: 13, color: 'var(--text-muted)' }}>acme-dataq-kv · all secrets encrypted at rest</div>
        </div>
        <Tag tone="indigo">Connected</Tag>
      </Card>
      <Card padding={0} style={{ overflow: 'hidden' }}>
        {secrets.map((s, i) => (
          <div key={s.name} style={{ display: 'flex', alignItems: 'center', gap: 12, padding: '14px 18px', borderTop: i ? '1px solid var(--divider)' : 'none' }}>
            <span style={{ flex: 1, fontFamily: 'var(--font-mono)', fontSize: 13, color: 'var(--text-primary)' }}>{s.name}</span>
            <Tag tone="outline">{s.type}</Tag>
            <span style={{ fontSize: 12, color: 'var(--text-muted)', width: 90, textAlign: 'right' }}>Rotated {s.rotated}</span>
            <Button variant="ghost" size="sm">Rotate</Button>
          </div>
        ))}
      </Card>
    </div>
  );
}

function NotificationsTab() {
  const { Switch } = DQset;
  const [a, setA] = React.useState(true), [b, setB] = React.useState(true), [c, setC] = React.useState(false);
  return (
    <div style={{ maxWidth: 520 }}>
      <Row label="Microsoft Teams" hint="Post failures and critical results to a channel webhook."><Switch checked={a} onChange={setA} /></Row>
      <Row label="Email digest" hint="Daily summary of suite health to all members."><Switch checked={b} onChange={setB} /></Row>
      <Row label="PagerDuty" hint="Page on-call for critical-severity breaches only."><Switch checked={c} onChange={setC} /></Row>
    </div>
  );
}

function DangerTab() {
  const { Button } = DQset;
  return (
    <div style={{ maxWidth: 560, border: '1px solid var(--red-border)', borderRadius: 'var(--radius-lg)', background: 'var(--red-bg)', padding: 20 }}>
      <div style={{ fontSize: 15, fontWeight: 600, color: 'var(--status-fail)' }}>Danger zone</div>
      <Row label="Pause all monitoring" hint="Suspends every scheduled suite and orchestration trigger."><Button variant="secondary" size="sm">Pause</Button></Row>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', gap: 24, padding: '16px 0 0' }}>
        <div style={{ maxWidth: 320 }}>
          <div style={{ fontSize: 14, fontWeight: 500, color: 'var(--text-primary)' }}>Delete workspace</div>
          <div style={{ fontSize: 13, color: 'var(--text-muted)', marginTop: 2 }}>Permanently removes all suites, runs and results.</div>
        </div>
        <Button variant="danger" size="sm">Delete</Button>
      </div>
    </div>
  );
}

function SettingsScreen() {
  const TABS = ['General', 'Secrets', 'Notifications', 'Danger zone'];
  const [tab, setTab] = React.useState('General');
  return (
    <div style={{ maxWidth: 1000, margin: '0 auto' }}>
      <h1 style={{ margin: '0 0 20px', fontSize: 24, fontWeight: 600, color: 'var(--text-primary)' }}>Workspace Settings</h1>
      <div style={{ display: 'grid', gridTemplateColumns: '200px 1fr', gap: 28, alignItems: 'start' }}>
        <SettingsTabs value={tab} onChange={setTab} items={TABS} />
        <div>
          {tab === 'General' && <GeneralTab />}
          {tab === 'Secrets' && <SecretsTab />}
          {tab === 'Notifications' && <NotificationsTab />}
          {tab === 'Danger zone' && <DangerTab />}
        </div>
      </div>
    </div>
  );
}

Object.assign(window, { SettingsScreen });
